from typing import TypedDict, Optional
from langgraph.graph import StateGraph, END

class TriageState(TypedDict):
    text: str
    category: Optional[str]
    confidence: Optional[float]
    fields: Optional[dict]

def node_classify(state: TriageState) -> TriageState:
    result = classify_chain.invoke({"text": state["text"]})
    return {"category": result.category, "confidence": result.confidence}

def node_extract_invoice(state: TriageState) -> TriageState:
    fields = make_extract_chain(InvoiceFields).invoke({"text": state["text"]})
    return {"fields": fields.model_dump()}

def node_extract_contract(state: TriageState) -> TriageState:
    fields = make_extract_chain(ContractFields).invoke({"text": state["text"]})
    return {"fields": fields.model_dump()}

def node_fallback(state: TriageState) -> TriageState:
    return {"fields": {"raw": state["text"][:500]}}

def route_by_category(state: TriageState) -> str:
    # Pure Python routing: no LLM call here
    return state["category"]

# Build the graph
graph = StateGraph(TriageState)
graph.add_node("classify", node_classify)
graph.add_node("extract_invoice", node_extract_invoice)
graph.add_node("extract_contract", node_extract_contract)
graph.add_node("fallback", node_fallback)

graph.set_entry_point("classify")
graph.add_conditional_edges(
    "classify",
    route_by_category,
    {
        "invoice": "extract_invoice",
        "contract": "extract_contract",
        "support_ticket": "fallback",
        "other": "fallback",
    }
)
for node in ["extract_invoice", "extract_contract", "fallback"]:
    graph.add_edge(node, END)

workflow = graph.compile()
result = workflow.invoke({"text": "Invoice #1042 from Acme Corp..."})

import time
import logging
from functools import wraps
from typing import Callable

logger = logging.getLogger("workflow")

def trace_node(fn: Callable) -> Callable:
    """Decorator: logs node entry/exit with timing."""
    @wraps(fn)
    def wrapper(state: dict) -> dict:
        start = time.perf_counter()
        logger.info("[%s] enter state_keys=%s", fn.__name__, list(state.keys()))
        try:
            result = fn(state)
            elapsed = (time.perf_counter() - start) * 1000
            logger.info("[%s] exit elapsed_ms=%.1f result_keys=%s",
                        fn.__name__, elapsed, list(result.keys()))
            return result
        except Exception as exc:
            logger.error("[%s] error: %s", fn.__name__, exc)
            raise
    return wrapper

# Apply to every node
@trace_node
def node_classify(state):
    result = classify_chain.invoke({"text": state["text"]})
    return {"category": result.category, "confidence": result.confidence}

@trace_node
def node_extract_invoice(state):
    fields = make_extract_chain(InvoiceFields).invoke({"text": state["text"]})
    return {"fields": fields.model_dump()}

# Example log output:
